const weekAgo = new Date(); weekAgo.setDate(weekAgo.getDate()-7);
const records = $input.all().map(i=>i.json).filter(r=>r.posted_date && new Date(r.posted_date)>=weekAgo);
// Group by company
const byCompany = {};
for (const r of records) {
  if (!byCompany[r.company]) byCompany[r.company] = [];
  byCompany[r.company].push(r);
}
return [{ json: { week: new Date().toISOString().slice(0,10), total_new_jobs: records.length, companies: Object.keys(byCompany).length, by_company: byCompany, records } }];

