const data = $('Filter Recent').first().json;
let analysis;
try { analysis = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { analysis = {}; }
return [{ json: { week: data.week, total_new_jobs: data.total_new_jobs, companies: data.companies, generated_at: new Date().toISOString(), ...analysis } }];

